
"use client"

import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Checkbox } from "@/components/ui/checkbox";
import { Gauge, Loader2, Mail, Lock, LogIn } from "lucide-react";
import { useRouter } from "next/navigation";
import { useAuth, useFirestore, useUser } from "@/firebase";
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  updateProfile,
  setPersistence,
  browserLocalPersistence,
  browserSessionPersistence,
  type User 
} from "firebase/auth";
import { doc, getDoc, setDoc } from "firebase/firestore";
import { useState, useEffect } from "react";
import { useToast } from "@/hooks/use-toast";

export default function Home() {
  const auth = useAuth();
  const db = useFirestore();
  const { user, isUserLoading } = useUser();
  const router = useRouter();
  const { toast } = useToast();
  
  const [isRegistering, setIsRegistering] = useState(false);
  const [loading, setLoading] = useState(false);
  const [mounted, setMounted] = useState(false);
  
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [username, setUsername] = useState("");
  const [rememberMe, setRememberMe] = useState(true);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (mounted && !isUserLoading && user) {
      router.replace('/dashboard');
    }
  }, [user, isUserLoading, mounted, router]);

  const initializeUserProfile = async (user: User, customUsername?: string) => {
    const userDocRef = doc(db, "users", user.uid);
    try {
      const userDoc = await getDoc(userDocRef);
      if (!userDoc.exists()) {
        await setDoc(userDocRef, {
          id: user.uid,
          username: customUsername || user.displayName || email.split('@')[0] || 'Shofer i Ri',
          city: 'Prishtinë',
          carBrand: 'BMW',
          carModel: 'M4 Competition',
          horsepower: 510,
          modifications: 'Stock',
          profilePhotoUrl: "",
          profileIcon: "speedometer",
          coverPhotoUrl: "",
          followedUserIds: [],
          isPremium: false,
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
        });
      }
    } catch (e) {
      console.error("Gabim gjatë inicializimit të profilit:", e);
    }
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      const persistence = rememberMe ? browserLocalPersistence : browserSessionPersistence;
      await setPersistence(auth, persistence);

      if (isRegistering) {
        if (!username) throw new Error("Ju lutem jepni një emër përdoruesi.");
        
        const result = await createUserWithEmailAndPassword(auth, email, password);
        
        await Promise.all([
          updateProfile(result.user, { displayName: username }),
          initializeUserProfile(result.user, username)
        ]);

        toast({
          title: "Llogaria u krijua!",
          description: "Mirë se vini në DriveRank Kosovë. Po ju ridrejtojmë...",
        });
      } else {
        const result = await signInWithEmailAndPassword(auth, email, password);
        await initializeUserProfile(result.user);
        
        toast({
          title: "Mirë se u ktheve!",
          description: "Po ju ridrejtojmë te dashboard-i.",
        });
      }
      
      router.push('/dashboard');
    } catch (error: any) {
      let message = "Ndodhi një gabim.";
      if (error.code === 'auth/email-already-in-use') message = "Ky email është i zënë.";
      if (error.code === 'auth/wrong-password') message = "Fjalëkalimi është i pasaktë.";
      if (error.code === 'auth/user-not-found') message = "Përdoruesi nuk u gjet.";
      if (error.code === 'auth/weak-password') message = "Fjalëkalimi duhet të jetë të paktën 6 karaktere.";
      
      toast({
        variant: "destructive",
        title: "Dështoi procesi",
        description: error.message || message,
      });
      setLoading(false);
    }
  };

  if (!mounted || isUserLoading) {
    return (
      <div className="flex flex-col min-h-screen items-center justify-center bg-background">
        <Loader2 className="h-10 w-10 animate-spin text-accent" />
      </div>
    );
  }

  if (user) return null;

  return (
    <div className="flex flex-col min-h-screen overflow-hidden p-6 gap-8 bg-background safe-bottom">
      <div className="mt-8 space-y-4">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-accent rounded-xl flex items-center justify-center neon-glow">
            <Gauge className="text-background w-6 h-6" />
          </div>
          <h1 className="text-2xl font-black tracking-tighter uppercase italic">
            DriveRank<span className="text-accent neon-text"> Kosovë</span>
          </h1>
        </div>
        <p className="text-muted-foreground text-sm font-medium leading-relaxed">
          Rrjeti i parë për performancën automobilistike në Kosovë.
        </p>
      </div>

      <div className="glass border-white/5 rounded-3xl p-6 shadow-2xl space-y-6">
        <div className="space-y-2">
          <h2 className="text-xl font-black italic uppercase tracking-tighter">
            {isRegistering ? "Krijo Llogari" : "Hyr në Llogari"}
          </h2>
          <p className="text-xs text-muted-foreground uppercase font-bold tracking-widest">
            {isRegistering ? "Bëhu pjesë e elitës" : "Vazhdo ku e ke lënë"}
          </p>
        </div>

        <form onSubmit={handleAuth} className="space-y-4" suppressHydrationWarning>
          {isRegistering && (
            <div className="space-y-2">
              <Label htmlFor="username" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Emri i Përdoruesit</Label>
              <div className="relative">
                <Input 
                  id="username"
                  type="text"
                  placeholder="p.sh. shofere_1"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  className="bg-white/5 border-white/10 rounded-xl h-12 pl-10"
                  required
                />
                <LogIn className="absolute left-3 top-3.5 w-4 h-4 text-muted-foreground" />
              </div>
            </div>
          )}

          <div className="space-y-2">
            <Label htmlFor="email" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Email</Label>
            <div className="relative">
              <Input 
                id="email"
                type="email"
                placeholder="emri@shembull.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="bg-white/5 border-white/10 rounded-xl h-12 pl-10"
                required
              />
              <Mail className="absolute left-3 top-3.5 w-4 h-4 text-muted-foreground" />
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="password" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Fjalëkalimi</Label>
            <div className="relative">
              <Input 
                id="password"
                type="password"
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="bg-white/5 border-white/10 rounded-xl h-12 pl-10"
                required
              />
              <Lock className="absolute left-3 top-3.5 w-4 h-4 text-muted-foreground" />
            </div>
          </div>

          <div className="flex items-center space-x-2 py-2">
            <Checkbox 
              id="remember" 
              checked={rememberMe}
              onCheckedChange={(checked) => setRememberMe(checked as boolean)}
              className="border-white/20 data-[state=checked]:bg-accent data-[state=checked]:text-background"
            />
            <Label 
              htmlFor="remember" 
              className="text-[11px] font-bold uppercase tracking-widest text-muted-foreground cursor-pointer select-none"
            >
              Më mbaj mend
            </Label>
          </div>

          <Button 
            type="submit"
            disabled={loading}
            className="w-full h-14 rounded-2xl bg-accent hover:bg-accent/80 text-background font-black italic uppercase text-base shadow-xl neon-glow mt-2 active:scale-95 transition-transform"
          >
            {loading ? (
              <Loader2 className="w-5 h-5 animate-spin" />
            ) : (
              isRegistering ? "REGJISTROHU DHE HYR" : "HYR TANI"
            )}
          </Button>
        </form>

        <div className="text-center pt-2">
          <button 
            type="button"
            onClick={() => setIsRegistering(!isRegistering)}
            className="text-xs font-bold uppercase tracking-widest text-accent hover:underline"
          >
            {isRegistering ? "Ke llogari? Hyr këtu" : "Nuk ke llogari? Regjistrohu"}
          </button>
        </div>
      </div>
    </div>
  );
}
